#include "fp_ft.h"

// Do not edit this file as it will be overwritten if HAMR codegen is rerun

void fp_ft_initialize(void);
void fp_ft_notify(microkit_channel channel);
void fp_ft_timeTriggered(void);

volatile sb_queue_TempControl_SysVerif_FanCmd_1_t *fanCmd_queue_1;
sb_queue_TempControl_SysVerif_FanCmd_1_Recv_t fanCmd_recv_queue;
volatile sb_queue_TempControl_SysVerif_FanAck_1_t *fanAck_queue_1;

#define PORT_FROM_MON 56

bool fanCmd_is_empty(void) {
  return sb_queue_TempControl_SysVerif_FanCmd_1_is_empty(&fanCmd_recv_queue);
}

bool get_fanCmd_poll(sb_event_counter_t *numDropped, TempControl_SysVerif_FanCmd *data) {
  return sb_queue_TempControl_SysVerif_FanCmd_1_dequeue((sb_queue_TempControl_SysVerif_FanCmd_1_Recv_t *) &fanCmd_recv_queue, numDropped, data);
}

bool get_fanCmd(TempControl_SysVerif_FanCmd *data) {
  sb_event_counter_t numDropped;
  return get_fanCmd_poll (&numDropped, data);
}

bool put_fanAck(const TempControl_SysVerif_FanAck *data) {
  sb_queue_TempControl_SysVerif_FanAck_1_enqueue((sb_queue_TempControl_SysVerif_FanAck_1_t *) fanAck_queue_1, (TempControl_SysVerif_FanAck *) data);

  return true;
}

void init(void) {
  sb_queue_TempControl_SysVerif_FanCmd_1_Recv_init(&fanCmd_recv_queue, (sb_queue_TempControl_SysVerif_FanCmd_1_t *) fanCmd_queue_1);

  sb_queue_TempControl_SysVerif_FanAck_1_init((sb_queue_TempControl_SysVerif_FanAck_1_t *) fanAck_queue_1);

  fp_ft_initialize();
}

void notified(microkit_channel channel) {
  switch (channel) {
    case PORT_FROM_MON:
      fp_ft_timeTriggered();
      break;
    default:
      fp_ft_notify(channel);
  }
}
